-- 0089_backfill_realized_revenue_ledger_brain_id.sql
--
-- AUDIT-REMEDIATION C3 (identity — THE UNLOCK) — backfill brain_id onto historical
-- realized_revenue_ledger rows, and populate connector_journey_stitch_map, so attribution can
-- produce rows. Runs as SUPERUSER (brain) — the ledger is append-only to brain_app (GRANT), so a
-- metadata-only UPDATE of brain_id (NOT a money column) must come from a superuser migration.
--
-- DETERMINISM + the join path:
--   The order ledger carries (brand_id, order_id) but NOT the customer id. The order->customer link
--   lives in the Bronze order.live.v1 events (now in the Iceberg lakehouse). This migration embeds the
--   (brand_id, order_id, storefront_customer_id, stitched_anon_id) tuples SNAPSHOTTED from Bronze
--   (StarRocks over brain_bronze_local.brain_bronze.collector_events) as a temp table, then:
--     1. Re-derives the per-brand identifier hash for each storefront_customer_id using the EXACT wire
--        format the resolver uses: sha256( salt || '||' || trim(storefront_customer_id) ), where the
--        DEV salt = sha256('brain-dev-identity-salt-v1||' || lower(brand_id)). (identity-core.resolveDevSaltHex)
--     2. Joins that hash to identity.identity_link (type='storefront_customer_id', is_active) -> brain_id.
--     3. Stamps brain_id on every NULL-brain_id ledger row for that (brand_id, order_id).
--     4. Upserts connector_journey_stitch_map for orders that carry a stitched_anon_id (so
--        silver_touchpoint.stitched_brain_id fills) — COALESCE so a later resolution never nulls it.
--
-- SAFETY / PROD POSTURE (why this is safe to run anywhere):
--   * The UPDATE only touches rows whose computed hash MATCHES an existing identity_link. In prod the
--     salt comes from KMS (not the dev derivation), so the computed hash will NOT match and ZERO rows
--     change — this is a NO-OP, never a corruption. (The forward path — LiveLedgerBridge + BrainIdResolver —
--     stamps new prod orders correctly; this historical backfill is a dev-data convenience.)
--   * brain_id is ledger METADATA, never a money value — stamping it cannot change any money math.
--   * Idempotent: re-running re-derives the same hashes and only fills still-NULL rows / COALESCEs the
--     stitch map. The temp table is dropped at COMMIT.
--   * pgcrypto.digest is required (already installed in this stack).

BEGIN;

CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TEMP TABLE _bf_order_customer (
  brand_id   uuid NOT NULL,
  order_id   text NOT NULL,
  sfid       text NOT NULL,
  anon_id    text
) ON COMMIT DROP;


-- Resolve each (brand_id, order_id) -> brain_id via the re-derived dev-salt hash -> identity_link.
CREATE TEMP TABLE _bf_order_brain ON COMMIT DROP AS
SELECT m.brand_id,
       m.order_id,
       m.anon_id,
       il.brain_id
FROM _bf_order_customer m
JOIN identity.identity_link il
  ON il.brand_id = m.brand_id
 AND il.identifier_type = 'storefront_customer_id'
 AND il.is_active = TRUE
 AND il.identifier_value = encode(
       digest(
         encode(digest('brain-dev-identity-salt-v1||' || lower(m.brand_id::text), 'sha256'), 'hex')
         || '||' || btrim(m.sfid),
         'sha256'),
       'hex');

-- 3. Stamp brain_id on still-NULL ledger rows (metadata-only; superuser bypasses the append-only GRANT).
WITH upd AS (
  UPDATE billing.realized_revenue_ledger rrl
     SET brain_id = b.brain_id
    FROM _bf_order_brain b
   WHERE rrl.brand_id = b.brand_id
     AND rrl.order_id = b.order_id
     AND rrl.brain_id IS NULL
  RETURNING 1
)
SELECT count(*) AS ledger_rows_stamped FROM upd;

-- 4. Populate connector_journey_stitch_map for orders carrying a stitched_anon_id (so
--    silver_touchpoint.stitched_brain_id fills). COALESCE preserves any existing brain_id.
SELECT b.brand_id, b.order_id, b.anon_id, b.brain_id
FROM _bf_order_brain b
WHERE b.anon_id IS NOT NULL AND b.anon_id <> ''
ON CONFLICT (brand_id, order_id) DO UPDATE
  SET stitched_anon_id = EXCLUDED.stitched_anon_id,
      brain_id         = COALESCE(EXCLUDED.brain_id, connector_journey_stitch_map.brain_id);

COMMIT;
